Rules.InvariantScript:
Set(
    currentUserLogin,
    LookUp(
        User,
        Email = EmailInput.Text And Password = PasswordInput.Text
    )
);
If(
    IsBlankOrError(currentUserLogin),
    Notify("Incorrect Username and Password");
    Set(
        ErrorLabel,
        true
    ),
    Set(
        currentUserEmail,
        currentUserLogin.Email
    );
    Set(
        currentUserRole,
        currentUserLogin.Role.Value
    );
    Switch(
        currentUserLogin.Role.Value,
        "Employee",
        Navigate(HomeScreen),
        "Manager",
        Navigate(HomeScreen),
        "Admin",
        Navigate(HomeScreen)
    )
);
Reset(EmailInput);
Reset(PasswordInput);
